   135→    rv = port_associate(portfd, PORT_SOURCE_FD, fd, events,
   136→        (void *)(uintptr_t)mask);
   137→    err = errno;
   138→
   139→    if (evport_debug)
   140→        fprintf(stderr, "%d (%s)\n", rv, rv == 0 ? "no error" : strerror(err));
